module.exports = /*#__PURE__*/JSON.parse('{"translations":{"krv":{"label":"개역한글","note":"성경전서 개역한글판 (대한성서공회, 1961). 라이선스: 대한성서공회 공식 저작권 FAQ에 따라 저작재산권 보호기간 50년 경과로 저작권료 지급 없이 사용 가능 공공저작물 (개역개정판은 해당 없음). 데이터 출처: scrollmapper/bible_databases (GitHub, 2025-languages branch, sources/ko/KorRV/KorRV.json, License: Public Domain)."},"kids":{"label":"쉬운말","note":"쉬운말 번역 준비 중입니다."}},"chapters":[{"chapter":1,"title":"복음을 부끄러워하지 말라","verses":{"krv":[{"n":1,"t":"하나님의 뜻으로 말미암아 그리스도 예수 안에 있는 생명의 약속대로 그리스도 예수의 사도 된 바울은"},{"n":2,"t":"사랑하는 아들 디모데에게 편지하노니 하나님 아버지와 그리스도 예수 우리 주께로부터 은혜와 긍휼과 평강이 네게 있을지어다"},{"n":3,"t":"나의 밤낮 간구하는 가운데 쉬지 않고 너를 생각하여 청결한 양심으로 조상적부터 섬겨 오는 하나님께 감사하고"},{"n":4,"t":"네 눈물을 생각하여 너 보기를 원함은 내 기쁨이 가득하게 하려 함이니"},{"n":5,"t":"이는 네 속에 거짓이 없는 믿음을 생각함이라 이 믿음은 먼저 네 외조모 로이스와 네 어머니 유니게 속에 있더니 네 속에도 있는 줄을 확신하노라"},{"n":6,"t":"그러므로 내가 나의 안수함으로 네 속에 있는 하나님의 은사를 다시 불일듯 하게 하기 위하여 너로 생각하게 하노니"},{"n":7,"t":"하나님이 우리에게 주신 것은 두려워하는 마음이 아니요 오직 능력과 사랑과 근신하는 마음이니"},{"n":8,"t":"그러므로 네가 우리 주의 증거와 또는 주를 위하여 갇힌 자 된 나를 부끄러워 말고 오직 하나님의 능력을 좇아 복음과 함께 고난을 받으라"},{"n":9,"t":"하나님이 우리를 구원하사 거룩하신 부르심으로 부르심은 우리의 행위대로 하심이 아니요 오직 자기 뜻과 영원한 때 전부터 그리스도 예수 안에서 우리에게 주신 은혜대로 하심이라"},{"n":10,"t":"이제는 우리 구주 그리스도 예수의 나타나심으로 말미암아 나타났으니 저는 사망을 폐하시고 복음으로써 생명과 썩지 아니할 것을 드러내신지라"},{"n":11,"t":"내가 이 복음을 위하여 반포자와 사도와 교사로 세우심을 입었노라"},{"n":12,"t":"이를 인하여 내가 또 이 고난을 받되 부끄러워하지 아니함은 나의 의뢰한 자를 내가 알고 또한 나의 의탁한 것을 그 날까지 저가 능히 지키실 줄을 확신함이라"},{"n":13,"t":"너는 그리스도 예수 안에 있는 믿음과 사랑으로써 내게 들은 바 바른 말을 본받아 지키고"},{"n":14,"t":"우리 안에 거하시는 성령으로 말미암아 네게 부탁한 아름다운 것을 지키라"},{"n":15,"t":"아시아에 있는 모든 사람이 나를 버린 이 일을 네가 아나니 그 중에 부겔로와 허모게네가 있느니라"},{"n":16,"t":"원컨대 주께서 오네시보로의 집에 긍휼을 베푸시옵소서 저가 나를 자주 유쾌케 하고 나의 사슬에 매인 것을 부끄러워 아니하여"},{"n":17,"t":"로마에 있을 때에 나를 부지런히 찾아 만났느니라"},{"n":18,"t":"(원컨대 주께서 저로 하여금 그 날에 주의 긍휼을 얻게 하여 주옵소서) 또 저가 에베소에서 얼마큼 나를 섬긴 것을 네가 잘 아느니라"}],"kids":[{"n":1,"t":"하나님의 뜻에 따라, 그리스도 예수님 안에 있는 생명의 약속을 따라 그리스도 예수님의 사도가 된 나 바울이,"},{"n":2,"t":"사랑하는 아들 디모데에게 편지를 써. 하나님 아버지와 그리스도 예수 우리 주님께로부터 은혜와 긍휼과 평강이 네게 함께하기를 빌어."},{"n":3,"t":"내가 밤낮으로 간구하는 가운데 너를 잊지 않고 늘 생각하면서, 조상 때부터 깨끗한 양심으로 섬겨 오는 하나님께 감사를 드려."},{"n":4,"t":"네 눈물을 기억하면서 너를 다시 만나기를 간절히 바라. 그것은 내 기쁨이 가득해지게 하려는 거야."},{"n":5,"t":"이렇게 너를 생각하는 것은, 네 안에 있는 거짓 없는 믿음 때문이야. 그 믿음은 먼저 네 외할머니 로이스와 네 어머니 유니게 안에 있던 것이고, 지금은 네 안에도 있다고 나는 확신해."},{"n":6,"t":"그러므로 내가 너에게 다시 일깨워. 내가 너에게 안수할 때 받은, 네 안에 있는 하나님의 은사(선물)를 불꽃처럼 다시 살아나게 해."},{"n":7,"t":"하나님께서 우리에게 주신 것은 두려워하는 마음이 아니라, 능력과 사랑과 절제하는 마음이야."},{"n":8,"t":"그러므로 너는 우리 주님에 대한 증언이나, 주님을 위해 갇혀 있는 나에 대해 부끄러워하지 마. 오히려 하나님의 능력을 따라 복음을 위해 함께 고난을 받아."},{"n":9,"t":"하나님께서 우리를 구원하시고 거룩하신 부르심으로 부르신 것은, 우리의 행위 때문이 아니라, 그분 자신의 뜻과 영원 전부터 그리스도 예수님 안에서 우리에게 주신 은혜를 따라 하신 거야."},{"n":10,"t":"이제 그 은혜가 우리 구주 그리스도 예수님의 나타나심으로 인해 분명히 드러났어. 그분은 죽음을 없애 버리시고, 복음으로 생명과 썩지 않는 것을 환히 드러내셨어."},{"n":11,"t":"나는 이 복음을 위해 전파자와 사도와 교사로 세움을 받았어."},{"n":12,"t":"이 일 때문에 내가 또 이런 고난을 받지만 부끄러워하지 않아. 내가 누구를 의지하는지 알고 있고, 내가 그분께 맡긴 것을 그 날까지 그분이 능히 지켜 주실 것을 확신하기 때문이야."},{"n":13,"t":"너는 그리스도 예수님 안에 있는 믿음과 사랑 안에서, 내게서 들은 바른 말씀을 본받아 잘 지켜."},{"n":14,"t":"우리 안에 머물러 계시는 성령을 통해, 너에게 맡겨진 그 아름다운 것을 잘 지켜."},{"n":15,"t":"아시아에 있는 모든 사람이 나를 버린 이 일을 너도 알고 있어. 그중에 부겔로와 허모게네가 있어."},{"n":16,"t":"주님께서 오네시보로의 집에 긍휼을 베풀어 주시기를 바라. 그는 자주 나를 위로해 주었고, 내가 사슬에 매여 있는 것을 부끄러워하지 않았어."},{"n":17,"t":"오히려 그가 로마에 있을 때에 나를 부지런히 찾아서 만났어."},{"n":18,"t":"(주님께서 그 날에 그가 주님의 긍휼을 얻게 해 주시기를 바라.) 또 그가 에베소에서 얼마나 많이 나를 섬겼는지는 네가 잘 알고 있어."}]}},{"chapter":2,"title":"그리스도의 좋은 군사","verses":{"krv":[{"n":1,"t":"내 아들아 그러므로 네가 그리스도 예수 안에 있는 은혜 속에서 강하고"},{"n":2,"t":"또 네가 많은 증인 앞에서 내게 들은 바를 충성된 사람들에게 부탁하라 저희가 또 다른 사람들을 가르칠 수 있으리라"},{"n":3,"t":"네가 그리스도 예수의 좋은 군사로 나와 함께 고난을 받을지니"},{"n":4,"t":"군사로 다니는 자는 자기 생활에 얽매이는 자가 하나도 없나니 이는 군사로 모집한 자를 기쁘게 하려 함이라"},{"n":5,"t":"경기하는 자가 법대로 경기하지 아니하면 면류관을 얻지 못할 것이며"},{"n":6,"t":"수고하는 농부가 곡식을 먼저 받는 것이 마땅하니라"},{"n":7,"t":"내 말하는 것을 생각하라 주께서 범사에 네게 총명을 주시리라"},{"n":8,"t":"나의 복음과 같이 다윗의 씨로 죽은 자 가운데서 다시 살으신 예수 그리스도를 기억하라"},{"n":9,"t":"복음을 인하여 내가 죄인과 같이 매이는 데까지 고난을 받았으나 하나님의 말씀은 매이지 아니하니라"},{"n":10,"t":"그러므로 내가 택하신 자를 위하여 모든 것을 참음은 저희로도 그리스도 예수 안에 있는 구원을 영원한 영광과 함께 얻게 하려 함이로라"},{"n":11,"t":"미쁘다 이 말이여, 우리가 주와 함께 죽었으면 또한 함께 살 것이요"},{"n":12,"t":"참으면 또한 함께 왕 노릇 할 것이요 우리가 주를 부인하면 주도 우리를 부인하실 것이라"},{"n":13,"t":"우리는 미쁨이 없을지라도 주는 일향 미쁘시니 자기를 부인하실 수 없으시리라"},{"n":14,"t":"너는 저희로 이 일을 기억하게 하여 말다툼을 하지 말라고 하나님 앞에서 엄히 명하라 이는 유익이 하나도 없고 도리어 듣는 자들을 망하게 함이니라"},{"n":15,"t":"네가 진리의 말씀을 옳게 분변하여 부끄러울 것이 없는 일꾼으로 인정된 자로 자신을 하나님 앞에 드리기를 힘쓰라"},{"n":16,"t":"망령되고 헛된 말을 버리라 저희는 경건치 아니함에 점점 나아가나니"},{"n":17,"t":"저희 말은 독한 창질의 썩어져 감과 같은데 그 중에 후메내오와 빌레도가 있느니라"},{"n":18,"t":"진리에 관하여는 저희가 그릇되었도다 부활이 이미 지나갔다 하므로 어떤 사람들의 믿음을 무너뜨리느니라"},{"n":19,"t":"그러나 하나님의 견고한 터는 섰으니 인침이 있어 일렀으되 주께서 자기 백성을 아신다 하며 또 주의 이름을 부르는 자마다 불의에서 떠날지어다 하였느니라"},{"n":20,"t":"큰 집에는 금과 은의 그릇이 있을 뿐 아니요 나무와 질그릇도 있어 귀히 쓰는 것도 있고 천히 쓰는 것도 있나니"},{"n":21,"t":"그러므로 누구든지 이런 것에서 자기를 깨끗하게 하면 귀히 쓰는 그릇이 되어 거룩하고 주인의 쓰심에 합당하며 모든 선한 일에 예비함이 되리라"},{"n":22,"t":"또한 네가 청년의 정욕을 피하고 주를 깨끗한 마음으로 부르는 자들과 함께 믿음과 사랑과 화평을 좇으라"},{"n":23,"t":"어리석고 무식한 변론을 버리라 이에서 다툼이 나는 줄 앎이라"},{"n":24,"t":"마땅히 주의 종은 다투지 아니하고 모든 사람을 대하여 온유하라 가르치기를 잘하며 참으며"},{"n":25,"t":"거역하는 자를 온유함으로 징계할지니 혹 하나님이 저희에게 회개함을 주사 진리를 알게 하실까 하며"},{"n":26,"t":"저희로 깨어 마귀의 올무에서 벗어나 하나님께 사로잡힌 바 되어 그 뜻을 좇게 하실까 함이라"}],"kids":[{"n":1,"t":"내 아들아, 그러므로 너는 그리스도 예수님 안에 있는 그 은혜 안에서 강해지도록 해."},{"n":2,"t":"또 네가 많은 증인 앞에서 내게 들은 것들을 신실한 사람들에게 맡겨. 그 사람들이 또 다른 사람들을 가르칠 수 있게 말이야."},{"n":3,"t":"너는 그리스도 예수님의 좋은 군사로서 나와 함께 고난을 받아."},{"n":4,"t":"군 복무를 하는 사람은 보통의 일상 일에 얽매이지 않아. 그것은 자기를 군사로 모집한 사람을 기쁘게 하기 위해서야."},{"n":5,"t":"경기하는 사람도 규칙대로 경기하지 않으면 면류관(상)을 얻지 못해."},{"n":6,"t":"수고하는 농부가 그 곡식을 먼저 받는 것이 마땅해."},{"n":7,"t":"내가 하는 말을 잘 생각해. 주님께서 모든 일에 너에게 깨달음을 주실 거야."},{"n":8,"t":"내가 전하는 복음대로, 다윗의 후손으로 (오시고) 죽은 사람들 가운데서 다시 살아나신 예수 그리스도를 기억해."},{"n":9,"t":"내가 이 복음 때문에 죄인처럼 사슬에 매이기까지 고난을 받고 있어. 그러나 하나님의 말씀은 매이지 않아."},{"n":10,"t":"그러므로 나는 택하심을 받은 사람들을 위해 모든 것을 참고 견뎌. 그것은 그들도 그리스도 예수님 안에 있는 구원을 영원한 영광과 함께 얻게 하려는 거야."},{"n":11,"t":"이 말은 신실해. \\"우리가 주님과 함께 죽었으면, 함께 살 것이고,"},{"n":12,"t":"참고 견디면 함께 왕 노릇 할 거야. 우리가 주님을 부인하면, 주님도 우리를 부인하실 거야."},{"n":13,"t":"우리가 신실하지 않더라도, 주님은 늘 신실하셔. 주님은 자기 자신을 부인하실 수 없으셔.\\""},{"n":14,"t":"너는 그들에게 이 일을 기억하게 하고, 하나님 앞에서 엄히 명령해서 말다툼을 하지 말라고 해. 그것은 아무런 유익이 없고, 오히려 듣는 사람들을 망하게 할 뿐이야."},{"n":15,"t":"너 자신을 하나님 앞에 인정받는 일꾼, 부끄러울 것이 없는 사람, 진리의 말씀을 바르게 다루는 사람으로 드리기를 힘써."},{"n":16,"t":"망령되고 헛된 말은 버려. 그런 말을 하는 사람들은 점점 더 경건하지 못한 길로 나아가."},{"n":17,"t":"그들의 말은 마치 곪아 가는 종기처럼 점점 퍼져 나가는데, 그중에 후메내오와 빌레도가 있어."},{"n":18,"t":"그들은 진리에서 빗나가서, \\"부활이 이미 지나갔다\\"고 말하면서 어떤 사람들의 믿음을 무너뜨리고 있어."},{"n":19,"t":"그러나 하나님의 견고한 터는 굳건히 서 있고, 거기에는 \\"주님께서는 자기 백성이 누구인지 아신다\\"는 인장과 \\"주님의 이름을 부르는 사람마다 불의에서 떠나라\\"는 인장이 새겨져 있어."},{"n":20,"t":"큰 집에는 금이나 은으로 된 그릇만 있는 게 아니라 나무나 흙으로 된 그릇도 있어. 어떤 것은 귀하게 쓰이고, 어떤 것은 천하게 쓰여."},{"n":21,"t":"그러므로 누구든지 이런 것들에서 자기를 깨끗하게 하면, 귀하게 쓰이는 그릇이 될 거야. 거룩하고 주인이 쓰시기에 알맞고, 모든 선한 일에 준비된 사람이 되는 거야."},{"n":22,"t":"또 너는 젊은 시절의 정욕을 피하고, 깨끗한 마음으로 주님을 부르는 사람들과 함께 믿음과 사랑과 평화를 추구해."},{"n":23,"t":"어리석고 무식한 논쟁은 멀리해. 그런 데서 다툼이 일어난다는 것을 알기 때문이야."},{"n":24,"t":"주님의 종은 다투면 안 돼. 오히려 모든 사람에게 온유해야 하고, 가르치기를 잘하며, 참을성이 있어야 해."},{"n":25,"t":"반대하는 사람들을 온유한 마음으로 바로잡아 주어야 해. 혹시 하나님께서 그들에게 회개하는 마음을 주셔서 진리를 알게 해 주실지도 모르고,"},{"n":26,"t":"또 그들이 정신을 차려서 마귀의 올무에서 벗어나, 하나님께 사로잡힌 사람이 되어 그분의 뜻을 따르게 될지도 몰라."}]}},{"chapter":3,"title":"마지막 때를 분별하라","verses":{"krv":[{"n":1,"t":"네가 이것을 알라 말세에 고통하는 때가 이르리니"},{"n":2,"t":"사람들은 자기를 사랑하며 돈을 사랑하며 자긍하며 교만하며 훼방하며 부모를 거역하며 감사치 아니하며 거룩하지 아니하며"},{"n":3,"t":"무정하며 원통함을 풀지 아니하며 참소하며 절제하지 못하며 사나우며 선한 것을 좋아 아니하며"},{"n":4,"t":"배반하여 팔며 조급하며 자고하며 쾌락을 사랑하기를 하나님 사랑하는 것보다 더하며"},{"n":5,"t":"경건의 모양은 있으나 경건의 능력은 부인하는 자니 이같은 자들에게서 네가 돌아서라"},{"n":6,"t":"저희 중에 남의 집에 가만히 들어가 어리석은 여자를 유인하는 자들이 있으니 그 여자는 죄를 중히 지고 여러 가지 욕심에 끌린 바 되어"},{"n":7,"t":"항상 배우나 마침내 진리의 지식에 이를 수 없느니라"},{"n":8,"t":"얀네와 얌브레가 모세를 대적한 것 같이 저희도 진리를 대적하니 이 사람들은 그 마음이 부패한 자요 믿음에 관하여는 버리운 자들이라"},{"n":9,"t":"그러나 저희가 더 나가지 못할 것은 저 두 사람의 된 것과 같이 저희 어리석음이 드러날 것임이니라"},{"n":10,"t":"나의 교훈과 행실과 의향과 믿음과 오래 참음과 사랑과 인내와"},{"n":11,"t":"핍박과 고난과 또한 안디옥과 이고니온과 루스드라에서 당한 일과 어떠한 핍박 받은 것을 네가 과연 보고 알았거니와 주께서 이 모든 것 가운데서 나를 건지셨느니라"},{"n":12,"t":"무릇 그리스도 예수 안에서 경건하게 살고자 하는 자는 핍박을 받으리라"},{"n":13,"t":"악한 사람들과 속이는 자들은 더욱 악하여져서 속이기도 하고 속기도 하나니"},{"n":14,"t":"그러나 너는 배우고 확신한 일에 거하라 네가 뉘게서 배운 것을 알며"},{"n":15,"t":"또 네가 어려서부터 성경을 알았나니 성경은 능히 너로 하여금 그리스도 예수 안에 있는 믿음으로 말미암아 구원에 이르는 지혜가 있게 하느니라"},{"n":16,"t":"모든 성경은 하나님의 감동으로 된 것으로 교훈과 책망과 바르게 함과 의로 교육하기에 유익하니"},{"n":17,"t":"이는 하나님의 사람으로 온전케 하며 모든 선한 일을 행하기에 온전케 하려 함이니라"}],"kids":[]}},{"chapter":4,"title":"선한 싸움을 마쳤다","verses":{"krv":[{"n":1,"t":"하나님 앞과 산 자와 죽은 자를 심판하실 그리스도 예수 앞에서 그의 나타나실 것과 그의 나라를 두고 엄히 명하노니"},{"n":2,"t":"너는 말씀을 전파하라 때를 얻든지 못 얻든지 항상 힘쓰라 범사에 오래 참음과 가르침으로 경책하며 경계하며 권하라"},{"n":3,"t":"때가 이르리니 사람이 바른 교훈을 받지 아니하며 귀가 가려워서 자기의 사욕을 좇을 스승을 많이 두고"},{"n":4,"t":"또 그 귀를 진리에서 돌이켜 허탄한 이야기를 좇으리라"},{"n":5,"t":"그러나 너는 모든 일에 근신하여 고난을 받으며 전도인의 일을 하며 네 직무를 다하라"},{"n":6,"t":"관제와 같이 벌써 내가 부음이 되고 나의 떠날 기약이 가까웠도다"},{"n":7,"t":"내가 선한 싸움을 싸우고 나의 달려갈 길을 마치고 믿음을 지켰으니"},{"n":8,"t":"이제 후로는 나를 위하여 의의 면류관이 예비되었으므로 주 곧 의로우신 재판장이 그 날에 내게 주실 것이니 내게만 아니라 주의 나타나심을 사모하는 모든 자에게니라"},{"n":9,"t":"너는 어서 속히 내게로 오라"},{"n":10,"t":"데마는 이 세상을 사랑하여 나를 버리고 데살로니가로 갔고 그레스게는 갈라디아로, 디도는 달마디아로 갔고"},{"n":11,"t":"누가만 나와 함께 있느니라 네가 올 때에 마가를 데리고 오라 저가 나의 일에 유익하니라"},{"n":12,"t":"두기고는 에베소로 보내었노라"},{"n":13,"t":"네가 올 때에 내가 드로아 가보의 집에 둔 겉옷을 가지고 오고 또 책은 특별히 가죽 종이에 쓴 것을 가져오라"},{"n":14,"t":"구리 장색 알렉산더가 내게 해를 많이 보였으매 주께서 그 행한 대로 저에게 갚으시리니"},{"n":15,"t":"너도 저를 주의하라 저가 우리 말을 심히 대적하였느니라"},{"n":16,"t":"내가 처음 변명할 때에 나와 함께 한 자가 하나도 없고 다 나를 버렸으나 저희에게 허물을 돌리지 않기를 원하노라"},{"n":17,"t":"주께서 내 곁에 서서 나를 강건케 하심은 나로 말미암아 전도의 말씀이 온전히 전파되어 이방인으로 듣게 하려 하심이니 내가 사자의 입에서 건지웠느니라"},{"n":18,"t":"주께서 나를 모든 악한 일에서 건져내시고 또 그의 천국에 들어가도록 구원하시리니 그에게 영광이 세세무궁토록 있을지어다 아멘"},{"n":19,"t":"브리스가와 아굴라와 및 오네시보로의 집에 문안하라"},{"n":20,"t":"에라스도는 고린도에 머물렀고 드로비모는 병듦으로 밀레도에 두었노니"},{"n":21,"t":"겨울 전에 너는 어서 오라 으불로와 부데와 리노와 글라우디아와 모든 형제가 다 네게 문안하느니라"},{"n":22,"t":"나는 주께서 네 심령에 함께 계시기를 바라노니 은혜가 너희와 함께 있을지어다"}],"kids":[]}}]}');

